  `quantity` int NOT NULL DEFAULT '1',
  `added_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `album_id` int DEFAULT NULL,
  `product_type` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `unit_price` decimal(10,2) NOT NULL,
  PRIMARY KEY (`cart_item_id`),
  KEY `version_id_idx` (`version_id`),
  KEY `album_id2_idx` (`album_id`),
  KEY `user_id2_idx` (`user_id`),
  CONSTRAINT `album_id2` FOREIGN KEY (`album_id`) REFERENCES `albums` (`album_id`),
  CONSTRAINT `user_id2` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`),
  CONSTRAINT `version_id` FOREIGN KEY (`version_id`) REFERENCES `album_versions` (`version_id`)
) ENGINE=InnoDB AUTO_INCREMENT=81 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
