/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `cart_BEFORE_INSERT` BEFORE INSERT ON `cart` FOR EACH ROW BEGIN
    DECLARE error_message VARCHAR(255);
    
    -- Проверяем логику заполнения полей
    IF NEW.product_type = 'album_version' THEN
        -- Для версий должен быть заполнен version_id, а album_id = NULL
        IF NEW.version_id IS NULL THEN
            SET error_message = 'Для product_type="album_version" необходимо указать version_id';
            SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = error_message;
        END IF;
        
        IF NEW.album_id IS NOT NULL THEN
            SET error_message = 'Для product_type="album_version" поле album_id должно быть NULL';
            SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = error_message;
        END IF;
        
    ELSEIF NEW.product_type = 'album' THEN
        -- Для альбомов должен быть заполнен album_id, а version_id = NULL
        IF NEW.album_id IS NULL THEN
            SET error_message = 'Для product_type="album" необходимо указать album_id';
            SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = error_message;
        END IF;
        
        IF NEW.version_id IS NOT NULL THEN
            SET error_message = 'Для product_type="album" поле version_id должно быть NULL';
            SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = error_message;
        END IF;
        
    ELSE
        -- Неправильный product_type
        SET error_message = 'product_type может быть только "album" или "album_version"';
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = error_message;
    END IF;
END */;;
DELIMITER ;
