CREATE DEFINER=`root`@`localhost` PROCEDURE `customer_add_to_cart`(
    IN p_user_id INT,
    IN p_version_id INT,
    IN p_quantity INT
)
BEGIN
    INSERT INTO cart (user_id, version_id, quantity, added_at, album_id, product_type, unit_price)
    SELECT 
        p_user_id,
        p_version_id,
        p_quantity,
        NOW(),
        a.album_id,
        'album',
        a.base_price * av.price_modifier
    FROM albums a
    JOIN album_versions av ON a.album_id = av.album_id
    WHERE av.version_id = p_version_id;
END ;;
